import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('Center Card', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('container uses flexbox', () => {
    const container = screen.getByTestId('container');
    const styles = getComputedStyle(container);
    expect(styles.display).toBe('flex');
  });

  it('container centres horizontally', () => {
    const container = screen.getByTestId('container');
    const styles = getComputedStyle(container);
    expect(styles.justifyContent).toBe('center');
  });

  it('container centres vertically', () => {
    const container = screen.getByTestId('container');
    const styles = getComputedStyle(container);
    expect(styles.alignItems).toBe('center');
  });

  it('container fills viewport height', () => {
    const container = screen.getByTestId('container');
    const styles = getComputedStyle(container);
    expect(styles.minHeight).toBe('100vh');
  });

  it('container has grey background', () => {
    const container = screen.getByTestId('container');
    const styles = getComputedStyle(container);
    expect(styles.backgroundColor).toBe('rgb(243, 244, 246)');
  });

  it('card has max-width of 24rem', () => {
    const card = screen.getByTestId('card');
    const styles = getComputedStyle(card);
    expect(styles.maxWidth).toBe('24rem');
  });

  it('card has border-radius', () => {
    const card = screen.getByTestId('card');
    const styles = getComputedStyle(card);
    expect(styles.borderRadius).toBe('0.75rem');
  });

  it('card has white background', () => {
    const card = screen.getByTestId('card');
    const styles = getComputedStyle(card);
    expect(styles.backgroundColor).toBe('rgb(255, 255, 255)');
  });
});

